lower = 霧の島の洞窟Ｂ２
level = 29
bgm = evil
margin = 1
shadow = dark
sky = black
outfield = soil
blank = rock
roof = stone
antiWarp = true

; 画像パーツ
━ = soil
　 = soil
〰 = water
❑ = cube
☗ = upstair
☖ = arch
⧻ = fence
︻ = panel
㊦ = ladderd
⑷ = br_luc

; 敵情報
monsters = パイレーツ,キャプテン,モンストラスバット,バンパイアバット,バンパイアラット,ボーパルハムスター

; 移動ポイント
(A) = map:霧の島・地上, x:8, y:10, way:w, symbol:upstair, ask:Leave the dungeon?
(B) = map:霧の島・地上, x:11, y:0, way:e, symbol:upstair, ask:Leave the dungeon?
(C) = map:霧の島・地上, x:5, y:2, way:s, symbol:upstair, ask:Leave the dungeon?

; 宝箱
box[1] = 黄金の人魚像,金貨（超特大）,金貨（超特大）,金貨（特大）,金貨（特大）,金貨（大）,金貨（大）

