;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

switchFence(0, 7, "n", "close");
switchFence(0, 7, "s", "close");

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4]

;-------------------------------------------------------------------------------
*event_1
;[exp] map.pos[0][7].s.type == "wall"

@se f=kacha
@wait time=800
@se f=fence
@switchfence x=0 y=7 way=s mode=switch

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] map.pos[0][7].n.type == "wall"

@se f=kacha
@wait time=800
@se f=fence
@switchfence x=0 y=7 way=n mode=switch

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@notice text="There was graffiti on the wall that read:<r>If you leave this floor, the door will close again. Is there any way to open the door opposite without leaving this floor?"

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("luck", 1)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had luck permanently increased by 1!"'

[eventoff]
;-------------------------------------------------------------------------------
